manifest_content:
{
  "name": "caveman-installer",
  "version": "0.1.0",
  "description": "Caveman installer — detects your AI coding agents and installs caveman for each one.",
  "license": "MIT",
  "author": "Julius Brussee",
  "homepage": "https://github.com/JuliusBrussee/caveman",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/JuliusBrussee/caveman.git"
  },
  "bugs": {
    "url": "https://github.com/JuliusBrussee/caveman/issues"
  },
  "bin": {
    "caveman": "./bin/install.js"
  },
  "engines": {
    "node": ">=18"
  },
  "scripts": {
    "test": "node --test tests/installer/*.test.mjs"
  },
  "files": [
    "bin/",
    "src/",
    "agents/",
    "skills/",
    "plugins/",
    "commands/",
    "dist/caveman.skill",
    "README.md",
    "LICENSE"
  ]
}

{
  "name": "@openai/codex-plugin-cc",
  "version": "1.0.5",
  "private": true,
  "type": "module",
  "description": "Use Codex from Claude Code to review code or delegate tasks.",
  "license": "Apache-2.0",
  "engines": {
    "node": ">=18.18.0"
  },
  "scripts": {
    "bump-version": "node scripts/bump-version.mjs",
    "check-version": "node scripts/bump-version.mjs --check",
    "prebuild": "mkdir -p plugins/codex/.generated/app-server-types && codex app-server generate-ts --out plugins/codex/.generated/app-server-types",
    "build": "tsc -p tsconfig.app-server.json",
    "test": "node --test tests/*.test.mjs"
  },
  "devDependencies": {
    "@types/node": "^25.5.0",
    "typescript": "^6.0.2"
  }
}

{
  "name": "immich-monorepo",
  "version": "3.0.1",
  "description": "Monorepo for Immich",
  "type": "module",
  "private": true,
  "scripts": {
    "format": "prettier --cache --check i18n/",
    "format:fix": "prettier --cache --write --list-different i18n"
  },
  "packageManager": "pnpm@11.6.0",
  "engines": {
    "pnpm": ">=10.0.0"
  },
  "devDependencies": {
    "prettier": "^3.8.3",
    "prettier-plugin-sort-json": "^4.2.0"
  }
}

{
  "name": "presenton",
  "version": "0.8.7",
  "presentationExportVersion": "v0.3.6",
  "type": "module",
  "description": "Open-source AI presentation generator",
  "scripts": {
    "sync:presentation-export": "node scripts/sync-presentation-export.cjs",
    "sync:presentation-export:force": "node scripts/sync-presentation-export.cjs --force",
    "check:presentation-export": "node scripts/sync-presentation-export.cjs --check-only"
  },
  "dependencies": {
    "@llamaindex/liteparse": "^1.5.2",
    "sharp": "^0.34.5"
  }
}

{
  "name": "tech-interview-handbook",
  "repository": "git@github.com:yangshun/tech-interview-handbook.git",
  "author": "Yangshun Tay <tay.yang.shun@gmail.com>",
  "license": "MIT",
  "private": true,
  "workspaces": [
    "packages/*",
    "apps/*"
  ],
  "scripts": {
    "build": "vp run --cache -r build",
    "ci": "vp check && vp test && vp run --cache -r build",
    "clean": "vp cache clean",
    "dev:portal": "vp run --filter @tih/portal... dev",
    "dev": "vp run --filter @tih/website... dev",
    "prepare": "vp config"
  },
  "devDependencies": {
    "vite-plus": "catalog:"
  },
  "engines": {
    "node": "25.8.1",
    "pnpm": "10.32.1"
  },
  "packageManager": "pnpm@10.32.1"
}

{
  "name": "@spicetify/cli",
  "private": true,
  "type": "module",
  "scripts": {
    "build:wrapper": "node scripts/build-wrapper.mjs",
    "check:wrapper": "node scripts/build-wrapper.mjs --check",
    "fmt": "oxfmt scripts src/jsHelper/spicetifyWrapper package.json .oxfmtrc.json .oxlintrc.json",
    "fmt:check": "oxfmt --check scripts src/jsHelper/spicetifyWrapper package.json .oxfmtrc.json .oxlintrc.json",
    "lint": "oxlint ."
  },
  "devDependencies": {
    "esbuild": "0.25.11",
    "oxfmt": "0.56.0",
    "oxlint": "1.71.0",
    "oxlint-tsgolint": "0.23.0"
  },
  "engines": {
    "node": ">=18",
    "npm": "please-use-pnpm",
    "pnpm": ">=8",
    "yarn": "please-use-pnpm"
  },
  "packageManager": "pnpm@11.9.0"
}
